        // Initialize MobileNet
        async function initMobileNet() {
            try {
                mobilenetModel = await mobilenet.load({
                    version: 2,
                    alpha: 1.0
                });
                return true;
            } catch (error) {
                dbg.error('Failed to load MobileNet:', error);
                return false;
            }
        }

