        const adminContentState = {
            activeTab: 'users',
            currentPage: 1,
            totalPages: 1,
            searchQuery: '',
            searchTimeout: null,
            editingItem: null
        };

        function setupAdminTabs() {
            // Tab clicks
            document.querySelectorAll('.admin-tab').forEach(tab => {
                tab.addEventListener('click', () => switchAdminTab(tab.dataset.tab));
            });

            // Content search
            const contentSearch = document.getElementById('admin-content-search');
            contentSearch.addEventListener('input', () => {
                clearTimeout(adminContentState.searchTimeout);
                adminContentState.searchTimeout = setTimeout(() => {
                    adminContentState.searchQuery = contentSearch.value.trim();
                    adminContentState.currentPage = 1;
                    loadAdminContentTable();
                }, 350);
            });

            // Content pagination
            document.getElementById('admin-content-prev').addEventListener('click', () => {
                if (adminContentState.currentPage > 1) {
                    adminContentState.currentPage--;
                    loadAdminContentTable();
                }
            });
            document.getElementById('admin-content-next').addEventListener('click', () => {
                if (adminContentState.currentPage < adminContentState.totalPages) {
                    adminContentState.currentPage++;
                    loadAdminContentTable();
                }
            });

            // Add button
            document.getElementById('admin-content-add-btn').addEventListener('click', () => {
                openAdminContentModal(adminContentState.activeTab, null);
            });

            // Content modal close
            document.getElementById('admin-content-modal-close').addEventListener('click', closeAdminContentModal);
            document.getElementById('admin-content-modal-cancel').addEventListener('click', closeAdminContentModal);
            document.getElementById('admin-content-modal').addEventListener('click', (e) => {
                if (e.target === e.currentTarget) closeAdminContentModal();
            });

            // Content form submit
            document.getElementById('admin-content-form').addEventListener('submit', handleAdminContentSave);
        }

        function switchAdminTab(tab) {
            adminContentState.activeTab = tab;
            adminContentState.currentPage = 1;
            adminContentState.searchQuery = '';

            // Update tab active states
            document.querySelectorAll('.admin-tab').forEach(t => {
                t.classList.toggle('active', t.dataset.tab === tab);
            });

            // Show/hide content areas
            const usersPane = document.getElementById('admin-tab-users');
            const contentPane = document.getElementById('admin-tab-content');

            if (tab === 'users') {
                usersPane.classList.add('active');
                contentPane.classList.remove('active');
            } else {
                usersPane.classList.remove('active');
                contentPane.classList.add('active');
                // Update title + search placeholder
                const cfg = adminTabConfig[tab];
                document.getElementById('admin-content-title').textContent = cfg.label;
                document.getElementById('admin-content-search').value = '';
                document.getElementById('admin-content-search').placeholder = cfg.searchPlaceholder;
                // Update create button visibility
                document.getElementById('admin-create-user-btn').style.display = 'none';
                loadAdminContentTable();
            }

            // Show/hide create user button
            if (tab === 'users') {
                document.getElementById('admin-create-user-btn').style.display = '';
            }
        }

        async function loadAdminContentTable() {
            const tab = adminContentState.activeTab;
            const cfg = adminTabConfig[tab];
            if (!cfg) return;

            const thead = document.getElementById('admin-content-thead');
            const tbody = document.getElementById('admin-content-tbody');

            // Render header
            thead.innerHTML = '<tr>' +
                cfg.columns.map(c => `<th>${escapeHtml(c.label)}</th>`).join('') +
                '<th>Actions</th></tr>';

            tbody.innerHTML = `<tr><td colspan="${cfg.columns.length + 1}" class="admin-table-empty">Loading...</td></tr>`;

            try {
                const params = new URLSearchParams({ page: adminContentState.currentPage, limit: 15 });
                if (adminContentState.searchQuery) params.set('search', adminContentState.searchQuery);

                const res = await apiFetch(cfg.apiPath + '?' + params.toString());
                if (!res.ok) throw new Error('Failed to load data');
                const result = await res.json();

                const items = result.data || [];
                const pagination = result.pagination || {};
                adminContentState.totalPages = pagination.totalPages || 1;

                // Store items for click handlers
                window._adminContentItems = {};

                if (items.length === 0) {
                    tbody.innerHTML = `<tr><td colspan="${cfg.columns.length + 1}" class="admin-table-empty">No items found.</td></tr>`;
                } else {
                    tbody.innerHTML = items.map((item, idx) => {
                        window._adminContentItems[idx] = item;
                        const cells = cfg.columns.map(c => {
                            let val = item[c.key];
                            if (val !== null && val !== undefined && typeof val === 'object') val = JSON.stringify(val);
                            return `<td>${escapeHtml(String(val ?? ''))}</td>`;
                        }).join('');
                        return `<tr data-idx="${idx}" onclick="openAdminContentModal('${tab}', window._adminContentItems[${idx}])" style="cursor:pointer">
                            ${cells}
                            <td class="admin-actions-cell" onclick="event.stopPropagation()">
                                <div class="admin-actions">
                                    <button class="admin-action-btn admin-btn-edit" onclick="openAdminContentModal('${tab}', window._adminContentItems[${idx}])">Edit</button>
                                </div>
                            </td>
                        </tr>`;
                    }).join('');
                }

                // Pagination
                document.getElementById('admin-content-page-info').textContent = `Page ${adminContentState.currentPage} of ${adminContentState.totalPages}`;
                document.getElementById('admin-content-prev').disabled = adminContentState.currentPage <= 1;
                document.getElementById('admin-content-next').disabled = adminContentState.currentPage >= adminContentState.totalPages;
            } catch (err) {
                dbg.error('Admin content load error:', err);
                tbody.innerHTML = `<tr><td colspan="${cfg.columns.length + 1}" class="admin-table-empty">Failed to load data.</td></tr>`;
            }
        }

        function openAdminContentModal(tab, item) {
            const cfg = adminTabConfig[tab];
            if (!cfg) return;

            adminContentState.editingItem = item;
            const isEdit = !!item;
            const modal = document.getElementById('admin-content-modal');
            const title = document.getElementById('admin-content-modal-title');
            const fieldsContainer = document.getElementById('admin-content-form-fields');
            const msg = document.getElementById('admin-content-message');

            title.textContent = isEdit ? `Edit ${cfg.label.replace(/s$/, '')}` : `Create ${cfg.label.replace(/s$/, '')}`;
            msg.style.display = 'none';

            // Build form fields
            fieldsContainer.innerHTML = cfg.formFields
                .filter(f => !isEdit || !f.createOnly)
                .map(f => {
                    const val = isEdit ? (item[f.key] ?? '') : '';
                    const displayVal = (typeof val === 'object' && val !== null) ? JSON.stringify(val, null, 2) : val;
                    const req = f.required ? 'required' : '';
                    const disabled = (isEdit && f.createOnly) ? 'disabled' : '';

                    if (f.type === 'textarea') {
                        return `<div class="admin-form-field">
                            <label class="admin-form-label">${escapeHtml(f.label)}</label>
                            <textarea class="admin-form-input" name="${f.key}" rows="3" ${req} ${disabled} style="resize:vertical;min-height:60px">${escapeHtml(String(displayVal))}</textarea>
                        </div>`;
                    }
                    if (f.type === 'select') {
                        const opts = (f.options || []).map(o =>
                            `<option value="${o}" ${val === o ? 'selected' : ''}>${o}</option>`
                        ).join('');
                        return `<div class="admin-form-field">
                            <label class="admin-form-label">${escapeHtml(f.label)}</label>
                            <select class="admin-form-input" name="${f.key}" ${req}><option value="">--</option>${opts}</select>
                        </div>`;
                    }
                    return `<div class="admin-form-field">
                        <label class="admin-form-label">${escapeHtml(f.label)}</label>
                        <input class="admin-form-input" type="${f.type}" name="${f.key}" value="${escapeHtml(String(displayVal))}" ${f.step ? `step="${f.step}"` : ''} ${req} ${disabled}>
                    </div>`;
                }).join('');

            // Show/hide delete button for edit mode
            const deleteBtn = document.getElementById('admin-content-delete-btn');
            if (isEdit) {
                deleteBtn.style.display = 'block';
                deleteBtn.onclick = () => adminDeleteContentItem(tab, item.id);
            } else {
                deleteBtn.style.display = 'none';
                deleteBtn.onclick = null;
            }

            modal.style.display = 'flex';
        }

        function closeAdminContentModal() {
            document.getElementById('admin-content-modal').style.display = 'none';
            adminContentState.editingItem = null;
        }

        async function handleAdminContentSave(e) {
            e.preventDefault();
            const tab = adminContentState.activeTab;
            const cfg = adminTabConfig[tab];
            if (!cfg) return;

            const form = document.getElementById('admin-content-form');
            const msg = document.getElementById('admin-content-message');
            msg.style.display = 'none';

            const isEdit = !!adminContentState.editingItem;
            const body = {};

            cfg.formFields.forEach(f => {
                if (isEdit && f.createOnly) return;
                const el = form.elements[f.key];
                if (!el) return;
                let val = el.value;
                if (f.type === 'number' && val !== '') val = Number(val);
                if (val === '' && !f.required) val = null;
                body[f.key] = val;
            });

            try {
                let url = cfg.apiPath;
                let method = 'POST';
                if (isEdit) {
                    url += '/' + adminContentState.editingItem.id;
                    method = 'PUT';
                }

                const res = await apiFetch(url, {
                    method,
                    body: JSON.stringify(body)
                });

                if (!res.ok) {
                    const data = await res.json().catch(() => ({}));
                    throw new Error((data.error && data.error.message) || data.message || 'Failed to save');
                }

                msg.textContent = isEdit ? 'Updated successfully!' : 'Created successfully!';
                msg.className = 'admin-create-message success';
                msg.style.display = 'block';

                loadAdminContentTable();

                setTimeout(() => closeAdminContentModal(), 800);
            } catch (err) {
                dbg.error('Admin content save error:', err);
                msg.textContent = err.message || 'Failed to save.';
                msg.className = 'admin-create-message error';
                msg.style.display = 'block';
            }
        }

        async function adminDeleteContentItem(tab, id) {
            if (!(await showConfirmModal('Are you sure you want to delete this item? This cannot be undone.', { okLabel: 'Delete' }))) return;
            const cfg = adminTabConfig[tab];
            if (!cfg) return;

            try {
                const res = await apiFetch(cfg.apiPath + '/' + id, { method: 'DELETE' });
                if (!res.ok) {
                    const data = await res.json().catch(() => ({}));
                    throw new Error((data.error && data.error.message) || data.message || 'Failed to delete');
                }
                closeAdminContentModal();
                loadAdminContentTable();
            } catch (err) {
                dbg.error('Admin content delete error:', err);
                showToast(err.message, 'error');
            }
        }

        // HTML escape helper for admin table
        function escapeHtml(str) {
            if (!str) return '';
            const div = document.createElement('div');
            div.textContent = str;
            return div.innerHTML;
        }

        // ══════════════════════════════════════════════════════════════
        // WEARABLE FEATURE
        // ══════════════════════════════════════════════════════════════

        const _wearableMode = new URLSearchParams(location.search).get('wearable') === '1';

        const wearableState = {
            isRunning: false,
            steps: 0,
            calories: 0,
            hr: null,
            hrReadings: [],
            startTime: null,
            activeSecs: 0,
            timerInterval: null,
            motionListener: null,
            rising: false,
            lastStepTime: 0,
            // background tracking
            _accSecs: 0,        // accumulated secs before current run segment
            _runStartWall: null, // wall time when current segment started
            _bgStart: null,     // wall time when tab went to background
        };

        let _woWakeLock = null;

        async function _woRequestWakeLock() {
            if ('wakeLock' in navigator) {
                try {
                    _woWakeLock = await navigator.wakeLock.request('screen');
                    _woWakeLock.addEventListener('release', () => { _woWakeLock = null; });
                } catch (_) { /* not supported or denied */ }
            }
        }

        function _woReleaseWakeLock() {
            if (_woWakeLock) { _woWakeLock.release(); _woWakeLock = null; }
        }

        function _woHandleVisibility() {
            if (!wearableState.isRunning) return;

            if (document.visibilityState === 'hidden') {
                // Going to background — record when
                wearableState._bgStart = Date.now();
                // Freeze accumulated secs at current value
                if (wearableState._runStartWall) {
                    wearableState._accSecs += Math.round((Date.now() - wearableState._runStartWall) / 1000);
                    wearableState.activeSecs = wearableState._accSecs;
                    wearableState._runStartWall = null;
                }
            } else if (document.visibilityState === 'visible' && wearableState._bgStart) {
                // Returning to foreground
                const bgElapsed = Math.round((Date.now() - wearableState._bgStart) / 1000);
                wearableState._bgStart = null;

                if (bgElapsed > 2) {
                    // Add background time to active secs
                    wearableState._accSecs += bgElapsed;
                    wearableState.activeSecs = wearableState._accSecs;
                    // Estimate steps at ~90 steps/min (typical walking cadence)
                    const estimated = Math.round(bgElapsed * 1.5);
                    wearableState.steps += estimated;
                    const weightKg = (state && state.weight) || 70;
                    wearableState.calories = Math.round(wearableState.steps * 0.04 * (weightKg / 70));
                    _woSetStatus(`+${estimated} steps estimated while away`);
                    setTimeout(() => { if (wearableState.isRunning) _woSetStatus('Tracking...'); }, 3000);
                }

                // Resume wall-clock segment and re-request wake lock
                wearableState._runStartWall = Date.now();
                _woRequestWakeLock();
                _woUpdateUI();
            }
        }

        // ── Mobile overlay ────────────────────────────────────────────

        let _woOverlayInited = false;

        function initWearableOverlay() {
            const overlay = document.getElementById('wearable-overlay');
            if (!overlay) return;
            overlay.style.display = 'flex';
            document.body.style.overflow = 'hidden';

            // Hide normal app shell when launched from the app
            const appContainer = document.querySelector('.app-container');
            if (appContainer) appContainer.style.display = 'none';

            // Wire buttons only once
            if (!_woOverlayInited) {
                document.getElementById('wo-start-btn').addEventListener('click', _woToggleSession);
                document.getElementById('wo-hr-btn').addEventListener('click', _woStartHR);
                document.getElementById('wo-save-btn').addEventListener('click', _woSaveSession);
                document.getElementById('wo-hr-cancel').addEventListener('click', _woCancelHR);
                const closeBtn = document.getElementById('wo-close-btn');
                if (closeBtn) closeBtn.addEventListener('click', _woCloseOverlay);
                document.addEventListener('visibilitychange', _woHandleVisibility);
                _woOverlayInited = true;
            }

            _woUpdateUI();
            setTimeout(_woSyncUnsynced, 2000);
        }

        function _woCloseOverlay() {
            // Stop active session timer but keep step count (don't reset)
            if (wearableState.isRunning) {
                clearInterval(wearableState.timerInterval);
                _woReleaseWakeLock();
                wearableState.isRunning = false;
                const btn = document.getElementById('wo-start-btn');
                if (btn) {
                    btn.innerHTML = '<svg viewBox="0 0 24 24" fill="currentColor" width="20" height="20"><polygon points="5 3 19 12 5 21 5 3"/></svg><span>Start</span>';
                    btn.className = 'wo-btn wo-btn-start';
                }
            }
            const overlay = document.getElementById('wearable-overlay');
            if (overlay) overlay.style.display = 'none';
            const appContainer = document.querySelector('.app-container');
            if (appContainer) appContainer.style.display = '';
            document.body.style.overflow = '';
            // Refresh wearables data so new session shows immediately
            if (typeof _loadWearableData === 'function') _loadWearableData();
        }

        async function _woSyncUnsynced() {
            if (!state.accessToken) return;
            const key = userKey('fixit-wearable-sessions');
            const sessions = JSON.parse(localStorage.getItem(key) || '[]');
            const unsynced = sessions.filter(s => !s.synced);
            if (unsynced.length === 0) return;

            let uploaded = 0;
            for (const s of unsynced) {
                try {
                    await apiFetch('/wearable/session', {
                        method: 'POST',
                        body: JSON.stringify({
                            steps: s.steps || 0,
                            calories: s.calories || null,
                            hr_avg: s.hr_avg || null,
                            hr_readings: s.hr_readings || undefined,
                            active_secs: s.active_secs || s.activeSecs || 0,
                            session_date: s.date
                        })
                    });
                    s.synced = true;
                    uploaded++;
                } catch (e) { /* leave unsynced, try next time */ }
            }

            if (uploaded > 0) {
                localStorage.setItem(key, JSON.stringify(sessions));
                const toast = document.getElementById('wo-saved-msg');
                if (toast) {
                    toast.textContent = `${uploaded} session${uploaded > 1 ? 's' : ''} synced to your account.`;
                    toast.style.display = 'block';
                    setTimeout(() => { toast.style.display = 'none'; }, 4000);
                }
            }
        }

        async function _woToggleSession() {
            if (wearableState.isRunning) {
                _woPause();
            } else {
                await _woStart();
            }
        }

        async function _woStart() {
            // iOS 13+ requires a user-gesture-triggered permission call
            if (typeof DeviceMotionEvent !== 'undefined' &&
                typeof DeviceMotionEvent.requestPermission === 'function') {
                try {
                    const result = await DeviceMotionEvent.requestPermission();
                    if (result !== 'granted') {
                        _woSetStatus('Motion permission denied — check iOS Settings > Safari');
                        return;
                    }
                } catch (e) {
                    _woSetStatus('Could not request motion permission');
                    return;
                }
            }

            wearableState.isRunning = true;
            if (!wearableState.startTime) wearableState.startTime = Date.now();

            // Save accumulated secs so far, start a new wall-clock segment
            wearableState._accSecs = wearableState.activeSecs;
            wearableState._runStartWall = Date.now();

            wearableState.motionListener = _woHandleMotion;
            window.addEventListener('devicemotion', wearableState.motionListener);

            // Use wall-clock diff for accurate timing even when throttled in background
            wearableState.timerInterval = setInterval(() => {
                if (wearableState._runStartWall && !wearableState._bgStart) {
                    wearableState.activeSecs = wearableState._accSecs +
                        Math.round((Date.now() - wearableState._runStartWall) / 1000);
                }
                _woUpdateUI();
            }, 1000);

            await _woRequestWakeLock();

            const btn = document.getElementById('wo-start-btn');
            btn.classList.add('running');
            btn.querySelector('span').textContent = 'Pause';
            btn.querySelector('svg').innerHTML = '<rect x="6" y="4" width="4" height="16"/><rect x="14" y="4" width="4" height="16"/>';
            _woSetStatus('Tracking...');
        }

        function _woPause() {
            wearableState.isRunning = false;

            // Freeze accumulated secs at current value before stopping
            if (wearableState._runStartWall) {
                wearableState._accSecs += Math.round((Date.now() - wearableState._runStartWall) / 1000);
                wearableState.activeSecs = wearableState._accSecs;
                wearableState._runStartWall = null;
            }

            if (wearableState.motionListener) {
                window.removeEventListener('devicemotion', wearableState.motionListener);
                wearableState.motionListener = null;
            }
            clearInterval(wearableState.timerInterval);
            _woReleaseWakeLock();

            const btn = document.getElementById('wo-start-btn');
            btn.classList.remove('running');
            btn.querySelector('span').textContent = 'Resume';
            btn.querySelector('svg').innerHTML = '<polygon points="5 3 19 12 5 21 5 3"/>';
            _woSetStatus('Paused');

            if (wearableState.steps > 0) {
                document.getElementById('wo-save-btn').style.display = 'flex';
            }
        }

        function _woHandleMotion(event) {
            const a = event.accelerationIncludingGravity;
            if (!a || a.x === null) return;

            const mag = Math.sqrt((a.x || 0) ** 2 + (a.y || 0) ** 2 + (a.z || 0) ** 2);
            const THRESHOLD = 13.0;
            const COOLDOWN_MS = 300;

            if (mag > THRESHOLD && !wearableState.rising) {
                wearableState.rising = true;
            } else if (wearableState.rising && mag < THRESHOLD) {
                wearableState.rising = false;
                const now = Date.now();
                if (now - wearableState.lastStepTime > COOLDOWN_MS) {
                    wearableState.lastStepTime = now;
                    wearableState.steps++;
                    // ~0.04 kcal/step, scaled by weight
                    const weightKg = state.weight || 70;
                    wearableState.calories = Math.round(wearableState.steps * 0.04 * (weightKg / 70));
                    _woUpdateUI();
                }
            }
        }

        function _woUpdateUI() {
            const stepsEl = document.getElementById('wo-steps-display');
            if (stepsEl) stepsEl.textContent = wearableState.steps.toLocaleString();

            // Step ring (circumference ≈ 534.07)
            const arc = document.getElementById('wo-ring-arc');
            const overflow = document.getElementById('wo-ring-overflow');
            if (arc) {
                const GOAL = parseInt(localStorage.getItem('fixit-wearable-daily-goal')) || 10000;
                const goalLbl = document.getElementById('wo-goal-label');
                if (goalLbl) goalLbl.textContent = `Goal: ${GOAL.toLocaleString()}`;
                const pct = Math.min(wearableState.steps / GOAL, 1);
                arc.style.strokeDashoffset = (534.07 * (1 - pct)).toFixed(2);
                if (wearableState.steps >= GOAL) {
                    const successColor = getComputedStyle(document.documentElement).getPropertyValue('--accent-success').trim() || '#7d9a78';
                    arc.setAttribute('stroke', successColor);
                    if (overflow) {
                        const overflowPct = Math.min((wearableState.steps / GOAL) - 1, 1);
                        overflow.style.strokeDashoffset = (534.07 * (1 - overflowPct)).toFixed(2);
                        overflow.setAttribute('stroke', successColor);
                        overflow.style.display = '';
                    }
                } else {
                    arc.removeAttribute('stroke');
                    if (overflow) overflow.style.display = 'none';
                }
            }

            const calEl = document.getElementById('wo-cal-display');
            if (calEl) calEl.textContent = wearableState.calories;

            const hrEl = document.getElementById('wo-hr-display');
            if (hrEl) hrEl.textContent = wearableState.hr ? wearableState.hr : '—';

            const timeEl = document.getElementById('wo-time-display');
            if (timeEl) {
                const m = Math.floor(wearableState.activeSecs / 60);
                const s = wearableState.activeSecs % 60;
                timeEl.textContent = `${m}:${String(s).padStart(2, '0')}`;
            }
        }

        function _woSetStatus(msg) {
            const el = document.getElementById('wo-status');
            if (el) el.textContent = msg;
        }

        // ── HR measurement (camera PPG) ───────────────────────────────

        let _hrStream = null;
        let _hrFrameInterval = null;
        let _hrCountdownTimer = null;
        let _hrSamples = [];
        let _hrSecondsLeft = 30;

        async function _woStartHR() {
            // Stop the HR panel if already open
            if (_hrStream) { _woCancelHR(); return; }

            _woSetStatus('Requesting camera...');
            try {
                _hrStream = await navigator.mediaDevices.getUserMedia({
                    video: { facingMode: 'environment', width: { ideal: 320 }, height: { ideal: 240 } }
                });
            } catch (e) {
                _woSetStatus('Camera access denied');
                return;
            }

            // Try to enable rear torch (works on Android; limited on iOS)
            const track = _hrStream.getVideoTracks()[0];
            try {
                await track.applyConstraints({ advanced: [{ torch: true }] });
            } catch (e) { /* torch not available */ }

            const video = document.getElementById('wo-cam-video');
            video.srcObject = _hrStream;
            await video.play();

            const offCanvas = document.createElement('canvas');
            offCanvas.width = 32;
            offCanvas.height = 32;
            const offCtx = offCanvas.getContext('2d');

            _hrSamples = [];
            _hrSecondsLeft = 30;

            const panel = document.getElementById('wo-hr-panel');
            panel.style.display = 'flex';
            document.getElementById('wo-hr-countdown').textContent = '30s';
            document.getElementById('wo-hr-progress-fill').style.width = '0%';

            _woSetStatus('Measuring heart rate...');

            // Sample red channel at ~30 fps
            _hrFrameInterval = setInterval(() => {
                try {
                    offCtx.drawImage(video, 0, 0, 32, 32);
                    const px = offCtx.getImageData(0, 0, 32, 32).data;
                    let r = 0;
                    for (let i = 0; i < px.length; i += 4) r += px[i];
                    _hrSamples.push(r / (px.length / 4));
                } catch (e) { /* frame read error */ }
            }, 33);

            _hrCountdownTimer = setInterval(() => {
                _hrSecondsLeft--;
                document.getElementById('wo-hr-countdown').textContent = `${_hrSecondsLeft}s`;
                document.getElementById('wo-hr-progress-fill').style.width =
                    `${((30 - _hrSecondsLeft) / 30) * 100}%`;
                if (_hrSecondsLeft <= 0) _woFinishHR();
            }, 1000);
        }

        function _woFinishHR() {
            clearInterval(_hrFrameInterval);
            clearInterval(_hrCountdownTimer);
            _hrFrameInterval = null;
            _hrCountdownTimer = null;

            if (_hrStream) {
                _hrStream.getTracks().forEach(t => t.stop());
                _hrStream = null;
            }

            document.getElementById('wo-hr-panel').style.display = 'none';

            if (_hrSamples.length >= 60) {
                const bpm = _woCalcBPM(_hrSamples);
                if (bpm >= 40 && bpm <= 200) {
                    wearableState.hr = bpm;
                    wearableState.hrReadings.push({ time: Date.now(), bpm });
                    _woSetStatus(`HR: ${bpm} bpm ✓`);
                    _woUpdateUI();
                    if (wearableState.steps > 0 || bpm > 0) {
                        document.getElementById('wo-save-btn').style.display = 'flex';
                    }
                } else {
                    _woSetStatus('Could not read HR — try again');
                }
            } else {
                _woSetStatus('Too few samples — try again');
            }
        }

        function _woCancelHR() {
            clearInterval(_hrFrameInterval);
            clearInterval(_hrCountdownTimer);
            _hrFrameInterval = null;
            _hrCountdownTimer = null;

            if (_hrStream) {
                _hrStream.getTracks().forEach(t => t.stop());
                _hrStream = null;
            }

            document.getElementById('wo-hr-panel').style.display = 'none';
            _woSetStatus(wearableState.isRunning ? 'Tracking...' : 'Ready');
        }

        function _woCalcBPM(samples) {
            // Moving average smoothing (window = 5)
            const smooth = [];
            for (let i = 0; i < samples.length; i++) {
                let s = 0, c = 0;
                for (let j = Math.max(0, i - 5); j <= Math.min(samples.length - 1, i + 5); j++) {
                    s += samples[j]; c++;
                }
                smooth.push(s / c);
            }

            const mean = smooth.reduce((a, b) => a + b) / smooth.length;
            const peaks = [];

            for (let i = 2; i < smooth.length - 2; i++) {
                if (smooth[i] > mean &&
                    smooth[i] > smooth[i - 1] && smooth[i] > smooth[i - 2] &&
                    smooth[i] > smooth[i + 1] && smooth[i] > smooth[i + 2]) {
                    if (peaks.length === 0 || i - peaks[peaks.length - 1] > 8) {
                        peaks.push(i);
                    }
                }
            }

            if (peaks.length < 2) return 0;

            const intervals = [];
            for (let i = 1; i < peaks.length; i++) {
                intervals.push(peaks[i] - peaks[i - 1]);
            }
            const avgInterval = intervals.reduce((a, b) => a + b) / intervals.length;
            // Each sample ≈ 33 ms → BPM = 60000 / (avgInterval × 33)
            return Math.round(60000 / (avgInterval * 33));
        }

        async function _woSaveSession() {
            const { steps, calories, hr, hrReadings, activeSecs } = wearableState;
            if (steps === 0 && !hr) return;

            const sessionData = {
                steps,
                calories,
                hr_avg: hr || null,
                hr_readings: hrReadings.length > 0 ? hrReadings : undefined,
                active_secs: activeSecs,
            };

            // Try backend first
            let saved = false;
            if (state.accessToken) {
                try {
                    await apiFetch('/wearable/session', {
                        method: 'POST',
                        body: JSON.stringify(sessionData)
                    });
                    saved = true;
                } catch (e) { /* fall through to localStorage */ }
            }

            // Always write to localStorage as backup
            const key = userKey('fixit-wearable-sessions');
            const sessions = JSON.parse(localStorage.getItem(key) || '[]');
            sessions.unshift({
                ...sessionData,
                date: new Date().toISOString().split('T')[0],
                savedAt: Date.now(),
                synced: saved
            });
            if (sessions.length > 50) sessions.pop();
            localStorage.setItem(key, JSON.stringify(sessions));

            document.getElementById('wo-save-btn').style.display = 'none';
            const toast = document.getElementById('wo-saved-msg');
            toast.textContent = saved
                ? 'Saved! Check the Wearables tab on your computer.'
                : 'Saved locally — will sync next time you open this page logged in.';
            toast.style.display = 'block';
            setTimeout(() => { toast.style.display = 'none'; }, 5000);

            _woResetSession();
        }

        function _woResetSession() {
            if (wearableState.motionListener) {
                window.removeEventListener('devicemotion', wearableState.motionListener);
            }
            clearInterval(wearableState.timerInterval);
            _woReleaseWakeLock();

            Object.assign(wearableState, {
                isRunning: false,
                steps: 0,
                calories: 0,
                hr: null,
                hrReadings: [],
                startTime: null,
                activeSecs: 0,
                timerInterval: null,
                motionListener: null,
                rising: false,
                lastStepTime: 0,
                _accSecs: 0,
                _runStartWall: null,
                _bgStart: null,
            });

            const btn = document.getElementById('wo-start-btn');
            btn.classList.remove('running');
            btn.querySelector('span').textContent = 'Start';
            btn.querySelector('svg').innerHTML = '<polygon points="5 3 19 12 5 21 5 3"/>';
            _woSetStatus('Ready');
            _woUpdateUI();
        }

        // ── Desktop wearable screen ───────────────────────────────────

        let _wearableScreenInitialized = false;
        let _wearablePollInterval = null;

        function _isMobileDevice() {
            return /Android|webOS|iPhone|iPad|iPod|BlackBerry|IEMobile|Opera Mini/i.test(navigator.userAgent)
                || (navigator.maxTouchPoints > 1 && window.innerWidth < 1024);
        }

        async function initWearableScreen() {
            if (!_wearableScreenInitialized) {
                const isMobile = _isMobileDevice();
                const startCard   = document.getElementById('wr-start-card');
                const connectCard = document.getElementById('wr-connect-card');

                // Show the appropriate card based on device type
                if (isMobile) {
                    if (startCard)   startCard.style.display   = '';
                    if (connectCard) connectCard.style.display = 'none';
                    const startCountBtn = document.getElementById('wr-start-count-btn');
                    if (startCountBtn) startCountBtn.addEventListener('click', initWearableOverlay);
                } else {
                    if (startCard)   startCard.style.display   = 'none';
                    if (connectCard) connectCard.style.display = '';

                    const origin = location.origin;
                    const isPublicUrl = !origin.includes('localhost') &&
                                        !origin.includes('127.0.0.1') &&
                                        !origin.startsWith('file:');

                    const tabInfo  = document.getElementById('wr-tab-info');
                    const tabQr    = document.getElementById('wr-tab-qr');
                    const panelInfo = document.getElementById('wearable-setup-guide');
                    const panelQr   = document.getElementById('wearable-qr-section');

                    const showTab = (tab) => {
                        const isQr = tab === 'qr';
                        tabInfo.classList.toggle('wr-tab-active', !isQr);
                        tabQr.classList.toggle('wr-tab-active', isQr);
                        if (panelInfo) panelInfo.style.display = isQr ? 'none' : '';
                        if (panelQr)   panelQr.style.display   = isQr ? 'flex' : 'none';
                    };
                    if (tabInfo) tabInfo.addEventListener('click', () => showTab('info'));
                    if (tabQr)   tabQr.addEventListener('click',   () => showTab('qr'));

                    if (isPublicUrl) {
                        const wearableUrl = origin + '/index.html?wearable=1';
                        const urlEl = document.getElementById('wearable-qr-url');
                        if (urlEl) urlEl.textContent = wearableUrl;

                        const img     = document.getElementById('wearable-qr-img');
                        const loading = document.getElementById('wearable-qr-loading');
                        if (img) {
                            const qrUrl = `https://api.qrserver.com/v1/create-qr-code/?size=160x160&margin=8&data=${encodeURIComponent(wearableUrl)}`;
                            img.onload  = () => { img.style.display = 'block'; if (loading) loading.style.display = 'none'; };
                            img.onerror = () => { if (loading) loading.textContent = 'QR unavailable — use Copy below'; };
                            img.src = qrUrl;
                        }
                        const copyBtn = document.getElementById('wearable-copy-link');
                        if (copyBtn) {
                            copyBtn.addEventListener('click', () => {
                                navigator.clipboard.writeText(wearableUrl)
                                    .then(() => showToast('Link copied!', 'success'))
                                    .catch(() => showToast('Copy failed — select manually', 'error'));
                            });
                        }
                    } else {
                        if (tabQr) { tabQr.disabled = true; tabQr.title = 'Available on Railway (HTTPS)'; }
                    }
                }

                const refreshBtn = document.getElementById('wearable-refresh-btn');
                if (refreshBtn) refreshBtn.addEventListener('click', _loadWearableData);

                // ── Daily goal editor ──────────────────────────────────
                const editBtn    = document.getElementById('wr-goal-edit-btn');
                const editor     = document.getElementById('wr-goal-editor');
                const goalInput  = document.getElementById('wr-goal-input');
                const goalUnit   = document.getElementById('wr-goal-unit');
                const saveBtn    = document.getElementById('wr-goal-save-btn');
                const cancelBtn  = document.getElementById('wr-goal-cancel-btn');
                const gtypeBtns  = document.querySelectorAll('.wr-gtype-btn');

                let _goalType = 'steps';

                const _getGoalSteps = () => parseInt(localStorage.getItem('fixit-wearable-daily-goal')) || 10000;
                const _updateGoalDisplay = () => {
                    const g = _getGoalSteps();
                    const el = document.getElementById('wr-goal-display');
                    if (el) el.textContent = `${g.toLocaleString()} steps (${(g * 0.00076).toFixed(1)} km)`;
                };
                _updateGoalDisplay();

                gtypeBtns.forEach(btn => btn.addEventListener('click', () => {
                    _goalType = btn.dataset.type;
                    gtypeBtns.forEach(b => b.classList.toggle('wr-gtype-active', b === btn));
                    const currentSteps = _getGoalSteps();
                    if (_goalType === 'km') {
                        goalInput.value = (currentSteps * 0.00076).toFixed(1);
                        goalInput.step  = '0.5';
                        goalInput.min   = '0.1';
                        goalInput.max   = '150';
                        if (goalUnit) goalUnit.textContent = 'km';
                    } else {
                        goalInput.value = currentSteps;
                        goalInput.step  = '500';
                        goalInput.min   = '100';
                        goalInput.max   = '200000';
                        if (goalUnit) goalUnit.textContent = 'steps';
                    }
                }));

                if (editBtn) editBtn.addEventListener('click', () => {
                    goalInput.value = _getGoalSteps();
                    _goalType = 'steps';
                    gtypeBtns.forEach(b => b.classList.toggle('wr-gtype-active', b.dataset.type === 'steps'));
                    if (goalUnit) goalUnit.textContent = 'steps';
                    if (editor) editor.style.display = 'flex';
                });

                if (saveBtn) saveBtn.addEventListener('click', () => {
                    const raw = parseFloat(goalInput.value);
                    if (!raw || raw <= 0) return;
                    const steps = _goalType === 'km' ? Math.round(raw / 0.00076) : Math.round(raw);
                    localStorage.setItem('fixit-wearable-daily-goal', steps);
                    _updateGoalDisplay();
                    if (editor) editor.style.display = 'none';
                    _loadWearableData();
                    showToast(`Daily goal set to ${steps.toLocaleString()} steps`, 'success');
                });

                if (cancelBtn) cancelBtn.addEventListener('click', () => {
                    if (editor) editor.style.display = 'none';
                });
            }

            const loginLabel = document.getElementById('wearable-logged-in-as');
            if (loginLabel && state.user) loginLabel.textContent = `Logged in as: ${state.user.email}`;

            _wearableScreenInitialized = true;
            await _loadWearableData();

            if (!_wearablePollInterval) {
                _wearablePollInterval = setInterval(_loadWearableData, 60000);
            }
        }

        async function _loadWearableData() {
            if (state.accessToken) {
                try {
                    const [todayRes, sessionsRes] = await Promise.all([
                        apiFetch('/wearable/today'),
                        apiFetch('/wearable/sessions?limit=14')
                    ]);
                    if (!todayRes.ok || !sessionsRes.ok) throw new Error('API error');
                    const [todayData, sessions] = await Promise.all([
                        todayRes.json(),
                        sessionsRes.json()
                    ]);
                    _renderWearableToday(todayData);
                    _renderWearableSessions(sessions);
                    return;
                } catch (e) { /* fall through to localStorage */ }
            }

            // Fallback: localStorage
            const key = userKey('fixit-wearable-sessions');
            const all = JSON.parse(localStorage.getItem(key) || '[]');
            const today = new Date().toISOString().split('T')[0];
            const todaySessions = all.filter(s => s.date === today);

            const todaySummary = todaySessions.reduce((acc, s) => ({
                total_steps: (acc.total_steps || 0) + (s.steps || 0),
                avg_hr: s.hr_avg || s.hr || acc.avg_hr,
                total_calories: (acc.total_calories || 0) + (s.calories || 0),
                total_active_secs: (acc.total_active_secs || 0) + (s.active_secs || s.activeSecs || 0),
            }), {});

            _renderWearableToday(todaySummary);
            _renderWearableSessions(all);
        }

        function _renderWearableToday(data) {
            if (!data) return;
            const steps = data.total_steps || 0;
            const hr = data.avg_hr;
            const cal = data.total_calories || 0;
            const activeSecs = data.total_active_secs || 0;
            const distKm = (steps * 0.00076).toFixed(2);

            const el = (id, v) => { const e = document.getElementById(id); if (e) e.textContent = v; };
            el('today-steps', steps ? steps.toLocaleString() : '—');
            el('today-distance', steps ? `${distKm} km` : '— km');
            el('today-hr', hr ? `${hr}` : '—');
            el('today-calories', cal ? `${cal}` : '—');
            el('today-active', activeSecs ? `${Math.round(activeSecs / 60)}` : '—');

            const GOAL = parseInt(localStorage.getItem('fixit-wearable-daily-goal')) || 10000;
            const pct = Math.min(steps / GOAL, 1);
            const fillEl = document.getElementById('today-goal-fill');
            const pctEl = document.getElementById('today-goal-pct');
            if (fillEl) fillEl.style.width = `${(pct * 100).toFixed(0)}%`;
            if (pctEl) pctEl.textContent = `${(pct * 100).toFixed(0)}%`;

            // Motivational message based on progress
            const motivEl = document.getElementById('wr-motivation');
            if (motivEl && steps > 0) {
                let msg, tier;
                if (pct >= 1) {
                    msg = '🏆 Goal accomplished! Outstanding effort!';
                    tier = 'complete';
                } else if (pct >= 0.9) {
                    msg = '🔥 So close! Just ' + (GOAL - steps).toLocaleString() + ' more steps to go!';
                    tier = 'almost';
                } else if (pct >= 0.75) {
                    msg = '💪 Almost there — you\'re on fire!';
                    tier = 'almost';
                } else if (pct >= 0.5) {
                    msg = '⚡ Halfway there! Keep pushing!';
                    tier = 'halfway';
                } else if (pct >= 0.25) {
                    msg = '👟 Good progress! A quarter done!';
                    tier = 'started';
                } else {
                    msg = '🚀 Great start! Every step counts!';
                    tier = 'started';
                }
                motivEl.textContent = msg;
                motivEl.className = 'wr-motivation wr-motiv-' + tier;

                // Celebrate goal completion (once per day)
                const today = new Date().toISOString().split('T')[0];
                const celebKey = 'fixit-step-goal-celebrated-' + today;
                if (pct >= 1 && !localStorage.getItem(celebKey)) {
                    localStorage.setItem(celebKey, '1');
                    setTimeout(() => showToast('🏆 Daily step goal reached! Amazing work!', 'success', 5000), 400);
                }
            } else if (motivEl) {
                motivEl.textContent = '';
                motivEl.className = 'wr-motivation';
            }

            // Animate ring (r=88, cx=cy=120, circumference=552.92)
            const CIRCUMFERENCE = 552.92;
            const arc = document.getElementById('wr-ring-fill');
            const overflow = document.getElementById('wr-ring-overflow');
            if (arc) {
                arc.style.strokeDashoffset = (CIRCUMFERENCE * (1 - pct)).toFixed(2);
                if (steps >= GOAL) {
                    const successColor = getComputedStyle(document.documentElement).getPropertyValue('--accent-success').trim() || '#7d9a78';
                    arc.setAttribute('stroke', successColor);
                    if (overflow) {
                        const overflowPct = Math.min((steps / GOAL) - 1, 1);
                        overflow.style.strokeDashoffset = (CIRCUMFERENCE * (1 - overflowPct)).toFixed(2);
                        overflow.setAttribute('stroke', successColor);
                        overflow.style.display = '';

                        const tipArrow = document.getElementById('wr-tip-arrow');
                        if (tipArrow) {
                            const visualPct = Math.max(overflowPct, 0.025);
                            const angle = -Math.PI / 2 + visualPct * 2 * Math.PI;
                            const tx = (120 + 88 * Math.cos(angle)).toFixed(1);
                            const ty = (120 + 88 * Math.sin(angle)).toFixed(1);
                            const rotateDeg = (visualPct * 360).toFixed(1);
                            tipArrow.setAttribute('x', tx);
                            tipArrow.setAttribute('y', ty);
                            tipArrow.setAttribute('transform', `rotate(${rotateDeg}, ${tx}, ${ty})`);
                            tipArrow.style.display = '';
                        }
                    }
                } else {
                    arc.setAttribute('stroke', 'url(#wr-grad)');
                    if (overflow) overflow.style.display = 'none';
                    const tipArrow = document.getElementById('wr-tip-arrow');
                    if (tipArrow) tipArrow.style.display = 'none';
                }
            }
        }

        function _renderWearableInsights(sessions) {
            if (!sessions || sessions.length === 0) return;

            const GOAL = parseInt(localStorage.getItem('fixit-wearable-daily-goal')) || 10000;
            const today = new Date();
            const todayKey = today.toISOString().split('T')[0];

            // Build date → steps map
            const byDate = {};
            sessions.forEach(s => {
                const key = (s.date || s.session_date || '').toString().split('T')[0];
                if (key) byDate[key] = Number(s.steps || 0);
            });

            // ── Weekly summary (Mon → today) ──────────────────────────────
            const dayOfWeek = today.getDay(); // 0=Sun
            const daysFromMon = dayOfWeek === 0 ? 6 : dayOfWeek - 1;
            let weekTotal = 0, weekDaysWithData = 0, daysGoalHit = 0;
            for (let i = 0; i <= daysFromMon; i++) {
                const d = new Date(today);
                d.setDate(today.getDate() - i);
                const key = d.toISOString().split('T')[0];
                const steps = byDate[key] || 0;
                if (steps > 0) { weekTotal += steps; weekDaysWithData++; }
                if (steps >= GOAL) daysGoalHit++;
            }
            const weekAvg = weekDaysWithData > 0 ? Math.round(weekTotal / weekDaysWithData) : 0;

            // ── Step streak (consecutive goal days going back from today) ──
            let streak = 0;
            for (let i = 0; i < 365; i++) {
                const d = new Date(today);
                d.setDate(today.getDate() - i);
                const key = d.toISOString().split('T')[0];
                if ((byDate[key] || 0) >= GOAL) streak++;
                else break;
            }

            // Best streak (scan full history)
            const sortedDates = Object.keys(byDate).filter(k => byDate[k] >= GOAL).sort();
            let bestStreak = 0, run = 0, prevDate = null;
            sortedDates.forEach(k => {
                if (!prevDate) { run = 1; }
                else {
                    const diff = (new Date(k) - new Date(prevDate)) / 86400000;
                    run = diff === 1 ? run + 1 : 1;
                }
                if (run > bestStreak) bestStreak = run;
                prevDate = k;
            });
            bestStreak = Math.max(bestStreak, streak);

            // ── Personal best ─────────────────────────────────────────────
            let pbSteps = 0, pbDate = '';
            Object.entries(byDate).forEach(([k, v]) => {
                if (v > pbSteps) { pbSteps = v; pbDate = k; }
            });
            const isPbToday = pbDate === todayKey;

            // ── Render ────────────────────────────────────────────────────
            const set = (id, v) => { const e = document.getElementById(id); if (e) e.textContent = v; };

            set('wr-week-total', weekTotal ? weekTotal.toLocaleString() : '—');
            set('wr-week-avg',   weekAvg   ? weekAvg.toLocaleString()   : '—');
            set('wr-days-hit',   `${daysGoalHit} / ${daysFromMon + 1}`);
            set('wr-step-streak', streak > 0 ? `${streak}d` : '0d');

            set('wr-step-pb', pbSteps ? pbSteps.toLocaleString() : '—');
            const pbDateEl = document.getElementById('wr-pb-date');
            if (pbDateEl && pbDate) {
                const d = new Date(pbDate + 'T00:00:00');
                pbDateEl.textContent = isPbToday ? '🎉 set today!' :
                    d.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
            }

            // Highlight streak cell when on a streak
            const streakTile = document.getElementById('wr-step-streak')?.closest('.wr-insight-tile');
            if (streakTile) streakTile.classList.toggle('wr-insight-hot', streak >= 3);

            // Celebrate PB set today
            const pbKey = 'fixit-step-pb-celebrated-' + todayKey;
            if (isPbToday && pbSteps > 0 && !localStorage.getItem(pbKey)) {
                localStorage.setItem(pbKey, '1');
                setTimeout(() => showToast('🏅 New personal best! ' + pbSteps.toLocaleString() + ' steps!', 'success', 5000), 800);
            }
        }

        let _wrStepChartInstance = null;
        let _wrAllSessions = [];
        let _wrChartDays = 7;

        function _renderWearableStepChart(sessions, days) {
            _wrAllSessions = sessions || [];
            _wrChartDays = days || 7;

            const canvas = document.getElementById('wr-steps-chart');
            if (!canvas) return;

            const GOAL = parseInt(localStorage.getItem('fixit-wearable-daily-goal')) || 10000;
            const today = new Date();

            // Build a map of date → aggregated totals (sum across multiple sessions per day)
            const byDate = {};
            _wrAllSessions.forEach(s => {
                const d = (s.date || s.session_date || '').toString().split('T')[0];
                if (!d) return;
                if (!byDate[d]) byDate[d] = { steps: 0, calories: 0, activeSecs: 0 };
                byDate[d].steps     += Number(s.steps    || 0);
                byDate[d].calories  += Number(s.calories || 0);
                byDate[d].activeSecs += Number(s.activeSecs || s.active_secs || 0);
                if (s.hr || s.hr_avg) byDate[d].hr = s.hr || s.hr_avg;
            });

            // Build last N days oldest → newest
            const labels = [], stepsData = [], colors = [];
            for (let i = _wrChartDays - 1; i >= 0; i--) {
                const d = new Date(today);
                d.setDate(today.getDate() - i);
                const key = d.toISOString().split('T')[0];
                const label = _wrChartDays <= 7
                    ? d.toLocaleDateString('en-US', { weekday: 'short' })
                    : d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
                labels.push(label);
                const s = byDate[key];
                const steps = s ? Number(s.steps || 0) : 0;
                stepsData.push(steps);
                colors.push(steps >= GOAL ? 'rgba(125,154,120,0.85)' : steps > 0 ? 'rgba(201,169,98,0.75)' : 'rgba(255,255,255,0.06)');
            }

            if (_wrStepChartInstance) { _wrStepChartInstance.destroy(); _wrStepChartInstance = null; }

            // Store date keys for click handler
            const dateKeys = [];
            for (let i = _wrChartDays - 1; i >= 0; i--) {
                const d = new Date(today);
                d.setDate(today.getDate() - i);
                dateKeys.push(d.toISOString().split('T')[0]);
            }

            _wrStepChartInstance = new Chart(canvas, {
                type: 'bar',
                data: {
                    labels,
                    datasets: [{
                        label: 'Steps',
                        data: stepsData,
                        backgroundColor: colors,
                        borderColor: colors.map(c => c.replace('0.75', '1').replace('0.85', '1').replace('0.06', '0.15')),
                        borderWidth: 1,
                        borderRadius: 5,
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    onClick: (evt, elements) => {
                        if (!elements.length) return;
                        const idx = elements[0].index;
                        const key = dateKeys[idx];
                        const s = byDate[key];
                        _showWrDayDetail(key, s || null);
                    },
                    plugins: {
                        legend: { display: false },
                        tooltip: {
                            backgroundColor: '#1e1c18',
                            titleColor: '#c9a962',
                            bodyColor: '#ccc',
                            borderColor: '#333',
                            borderWidth: 1,
                            callbacks: {
                                label: ctx => {
                                    const v = ctx.parsed.y;
                                    if (!v) return 'No data';
                                    const pct = Math.round((v / GOAL) * 100);
                                    return `${v.toLocaleString()} steps (${pct}% of goal)`;
                                }
                            }
                        },
                        annotation: undefined
                    },
                    scales: {
                        x: {
                            ticks: { color: '#666', font: { size: 10 } },
                            grid: { display: false }
                        },
                        y: {
                            ticks: {
                                color: '#666',
                                font: { size: 10 },
                                callback: v => v >= 1000 ? (v / 1000).toFixed(0) + 'k' : v
                            },
                            grid: { color: 'rgba(255,255,255,0.04)' },
                            beginAtZero: true,
                        }
                    }
                }
            });

            // Period button wiring (only once)
            if (!canvas._wrPeriodWired) {
                canvas._wrPeriodWired = true;
                document.querySelectorAll('.wr-period-btn').forEach(btn => {
                    btn.addEventListener('click', () => {
                        document.querySelectorAll('.wr-period-btn').forEach(b => b.classList.remove('wr-period-active'));
                        btn.classList.add('wr-period-active');
                        _renderWearableStepChart(_wrAllSessions, parseInt(btn.dataset.days));
                        document.getElementById('wr-step-detail').style.display = 'none';
                    });
                });
            }
        }

        function _showWrDayDetail(dateKey, session) {
            const detailEl = document.getElementById('wr-step-detail');
            const dateEl   = document.getElementById('wr-detail-date');
            const stepsEl  = document.getElementById('wr-detail-steps');
            const distEl   = document.getElementById('wr-detail-dist');
            const calEl    = document.getElementById('wr-detail-cal');
            const activeEl = document.getElementById('wr-detail-active');
            if (!detailEl) return;

            const d = new Date(dateKey + 'T00:00:00');
            if (dateEl) dateEl.textContent = d.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });

            const steps = session ? Number(session.steps || 0) : 0;
            const cal   = session ? Math.round(session.calories || 0) : 0;
            const secs  = session ? (session.active_secs || session.activeSecs || 0) : 0;
            if (stepsEl) stepsEl.textContent = steps ? steps.toLocaleString() : '—';
            if (distEl)  distEl.textContent  = steps ? (steps * 0.00076).toFixed(2) : '—';
            if (calEl)   calEl.textContent   = cal   ? cal : '—';
            if (activeEl) activeEl.textContent = secs ? Math.round(secs / 60) : '—';

            detailEl.style.display = '';
        }

        function _renderWearableSessions(sessions) {
            // Insights: weekly summary, streak, personal best
            _renderWearableInsights(sessions);
            // Always render the step chart (even with no sessions)
            _renderWearableStepChart(sessions, _wrChartDays);

            const list = document.getElementById('wearable-sessions-list');
            if (!list) return;

            if (!sessions || sessions.length === 0) {
                list.innerHTML = '<div class="wr-empty">No sessions yet — start tracking on your phone</div>';
                return;
            }

            list.innerHTML = sessions.map(s => {
                const rawDate = (s.date || s.session_date || '').toString().split('T')[0];
                const d = new Date(rawDate + 'T00:00:00');
                const dateStr = !isNaN(d) ? d.toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric' }) : rawDate;
                const stepsNum = s.steps != null ? Number(s.steps) : 0;
                const steps = stepsNum ? stepsNum.toLocaleString() : '—';
                const dist = stepsNum ? `${(stepsNum * 0.00076).toFixed(2)} km` : '—';
                const hr = (s.hr_avg || s.hr) ? `${s.hr_avg || s.hr} bpm` : '—';
                const cal = s.calories ? `${Math.round(s.calories)} kcal` : '—';
                const activeSecs = s.active_secs || s.activeSecs;
                const active = activeSecs ? `${Math.round(activeSecs / 60)} min` : '—';

                return `<div class="wr-session-row">
                    <div class="wr-srow-date">${dateStr}</div>
                    <div class="wr-srow-steps">${steps}</div>
                    <div class="wr-srow-dist">${dist}</div>
                    <div class="wr-srow-chip">${cal}</div>
                    <div class="wr-srow-chip">${active}</div>
                    <div class="wr-srow-chip wr-srow-hr">${hr}</div>
                </div>`;
            }).join('');
        }

        // Auto-activate wearable overlay on mobile when ?wearable=1
        if (_wearableMode) {
            // Wait for DOM to be ready
            if (document.readyState === 'loading') {
                document.addEventListener('DOMContentLoaded', initWearableOverlay);
            } else {
                initWearableOverlay();
            }
        }

        // Initialize app
        init();
